function palette(i){return['#ef7b5d','#2f9b70','#3178d5','#d89a2b','#8d6bb8','#d6535d','#5aa7a7'][i%7]}function pie(items){const total=items.reduce((s,x)=>s+Number(x[1]||0),0);if(!total)return'<div class="empty">資料不足</div>';let a=-Math.PI/2,paths='';items.forEach((x,i)=>{const da=x[1]/total*Math.PI*2,b=a+da,x1=100+78*Math.cos(a),y1=100+78*Math.sin(a),x2=100+78*Math.cos(b),y2=100+78*Math.sin(b),large=da>Math.PI?1:0;paths+=`<path d="M100,100 L${x1},${y1} A78,78 0 ${large},1 ${x2},${y2} Z" fill="${palette(i)}"></path>`;a=b});return `<svg class="svg-chart" viewBox="0 0 200 200">${paths}<circle cx="100" cy="100" r="42" fill="white"></circle><text x="100" y="98" text-anchor="middle" font-size="12" fill="#758078">合計</text><text x="100" y="118" text-anchor="middle" font-size="14" font-weight="700">${Math.round(total).toLocaleString()}</text></svg><div class="legend">${items.filter(x=>x[1]>0).map((x,i)=>`<span><i style="background:${palette(i)}"></i>${esc(x[0])}</span>`).join('')}</div>`}
function bars(items){const max=Math.max(1,...items.map(x=>Number(x[1]||0))),n=Math.max(1,items.length),step=300/n,bw=Math.max(16,step*.55);return `<svg class="svg-chart" viewBox="0 0 360 210"><line x1="30" y1="175" x2="345" y2="175" stroke="#dfe4e1"/>${items.map((x,i)=>{const v=Number(x[1]||0),h=v/max*125,xx=35+i*step;return `<rect x="${xx}" y="${175-h}" width="${bw}" height="${h}" rx="6" fill="${palette(i)}"></rect><text x="${xx+bw/2}" y="195" text-anchor="middle" font-size="10">${esc(x[0])}</text>`}).join('')}</svg>`}
function line(items){if(!items.length)return'<div class="empty">資料不足</div>';const max=Math.max(1,...items.map(x=>Number(x[1]||0))),pts=items.map((x,i)=>`${35+i*(300/Math.max(1,items.length-1))},${170-Number(x[1]||0)/max*125}`).join(' ');return `<svg class="svg-chart" viewBox="0 0 360 210"><line x1="30" y1="175" x2="340" y2="175" stroke="#dfe4e1"/><polyline fill="none" stroke="#3178d5" stroke-width="4" points="${pts}"/>${items.map((x,i)=>{const xx=35+i*(300/Math.max(1,items.length-1)),yy=170-Number(x[1]||0)/max*125;return `<circle cx="${xx}" cy="${yy}" r="5" fill="#3178d5"></circle><text x="${xx}" y="197" text-anchor="middle" font-size="10">${esc(x[0])}</text>`}).join('')}</svg>`}
