function openExcelImport(){excelPreviewData=null;$('excelImportIntro').classList.remove('hidden');$('excelImportPreview').classList.add('hidden');$('excelFile').value='';openModal('excelImportModal')}
function cancelExcelPreview(){excelPreviewData=null;$('excelImportIntro').classList.remove('hidden');$('excelImportPreview').classList.add('hidden');$('excelFile').value=''}
function normHeader(v){return String(v??'').trim().replace(/\s+/g,'').replace(/[（）()]/g,m=>m==='（'?'(':m==='）'?')':m)}
function rowValue(row,names){const keys=Object.keys(row);for(const n of names){const nn=normHeader(n),k=keys.find(x=>normHeader(x)===nn);if(k!==undefined)return row[k]}return''}
function toNum(v){if(v===null||v===undefined||v==='')return 0;if(typeof v==='number')return Number.isFinite(v)?v:0;const n=Number(String(v).replace(/[,，NT$￥$%\s]/g,''));return Number.isFinite(n)?n:0}
function toBool(v,def=true){const x=String(v??'').trim().toLowerCase();if(!x)return def;return !['否','不','false','0','no','n'].includes(x)}
function excelDate(v){if(!v)return'';if(v instanceof Date&&!isNaN(v)){const y=v.getFullYear(),m=String(v.getMonth()+1).padStart(2,'0'),d=String(v.getDate()).padStart(2,'0');return`${y}-${m}-${d}`}if(typeof v==='number'&&window.XLSX?.SSF){const z=XLSX.SSF.parse_date_code(v);if(z)return`${z.y}-${String(z.m).padStart(2,'0')}-${String(z.d).padStart(2,'0')}`}const x=String(v).trim().replace(/[.年]/g,'/').replace(/月/g,'/').replace(/日/g,'').replace(/-/g,'/');const p=x.split('/').filter(Boolean).map(Number);if(p.length>=3&&p[0]>1900)return`${p[0]}-${String(p[1]).padStart(2,'0')}-${String(p[2]).padStart(2,'0')}`;const dt=new Date(v);return isNaN(dt)?'':dt.toISOString().slice(0,10)}
function excelSheetRows(wb,names){const actual=wb.SheetNames.find(n=>names.includes(String(n).trim()));if(!actual)return[];return XLSX.utils.sheet_to_json(wb.Sheets[actual],{defval:'',raw:true,cellDates:true}).filter(r=>Object.values(r).some(v=>v!==''&&v!==null&&v!==undefined))}
function parseExcelWorkbook(wb){const warnings=[];
 const debtRows=excelSheetRows(wb,['負債狀況','負債','信用卡']);
 const assetRows=excelSheetRows(wb,['資產狀況','資產']);
 const goalRows=excelSheetRows(wb,['存錢目標','目標']);
 const txRows=excelSheetRows(wb,['記帳','收支','交易']);
 const debtTypeRows=excelSheetRows(wb,['負債狀況分類','負債分類','負債類型']);
 const assetTypeRows=excelSheetRows(wb,['資產狀況分類','資產分類','資產類型']);
 const incRows=excelSheetRows(wb,['收入分類']);
 const expRows=excelSheetRows(wb,['支出分類']);
 const debts=debtRows.map((r,i)=>{let type=String(rowValue(r,['類型','負債類型'])||'其他').trim();const amount=toNum(rowValue(r,['剩餘金額','金額','目前卡費'])),payment=toNum(rowValue(r,['每期應繳','每期金額'])),currentDue=toNum(rowValue(r,['本期應繳']))||payment,currentPaid=toNum(rowValue(r,['本期已繳','已繳']));const name=String(rowValue(r,['名稱','卡片名稱'])||type).trim();if(!name)warnings.push(`負債第 ${i+2} 列缺少名稱`);return{id:uid()+i,type,name,amount,rate:toNum(rowValue(r,['年利率(%)','年利率','利率(%)','利率'])),terms:toNum(rowValue(r,['剩餘期數','期數'])),payment,currentDue,currentPaid:Math.min(currentPaid,currentDue||currentPaid),due:excelDate(rowValue(r,['下期繳費日','繳費截止日','下期繳款日期'])),note:String(rowValue(r,['備註'])||'').trim(),importedFromExcel:true}}).filter(x=>x.name&&x.amount>=0);
 const assets=assetRows.map((r,i)=>({id:uid()+1000+i,type:String(rowValue(r,['類型','資產類型'])||'其他').trim(),name:String(rowValue(r,['名稱','帳戶名稱'])||'資產').trim(),amount:toNum(rowValue(r,['金額','目前餘額','餘額'])),available:toBool(rowValue(r,['是否可用資產','計入可用資產']),true),note:String(rowValue(r,['備註'])||'').trim(),importedFromExcel:true})).filter(x=>x.name);
 const goals=goalRows.map((r,i)=>({id:uid()+2000+i,name:String(rowValue(r,['名稱','目標名稱'])||'存錢目標').trim(),target:toNum(rowValue(r,['目標金額'])),current:toNum(rowValue(r,['已存金額','目前已存'])),date:excelDate(rowValue(r,['預計完成日','目標日期'])),accountName:String(rowValue(r,['對應帳戶'])||'').trim(),note:String(rowValue(r,['備註'])||'').trim(),importedFromExcel:true})).filter(x=>x.name);
 const assetByName=new Map(assets.map(x=>[x.name,x]));const debtByName=new Map(debts.map(x=>[x.name,x]));const goalByName=new Map(goals.map(x=>[x.name,x]));
 const mapType=v=>{const x=String(v||'').trim();return x==='收入'?'income':x==='存款'?'saving':'expense'};
 const transactions=txRows.map((r,i)=>{const type=mapType(rowValue(r,['類型'])),assetName=String(rowValue(r,['帳戶','資產帳戶'])||'').trim(),cardName=String(rowValue(r,['信用卡','卡片'])||'').trim(),goalName=String(rowValue(r,['存錢目標','目標'])||'').trim(),date=excelDate(rowValue(r,['日期']));if(!date)warnings.push(`記帳第 ${i+2} 列日期無法辨識`);const a=assetByName.get(assetName),d=debtByName.get(cardName),g=goalByName.get(goalName);if(assetName&&!a)warnings.push(`記帳第 ${i+2} 列找不到帳戶「${assetName}」`);if(cardName&&!d)warnings.push(`記帳第 ${i+2} 列找不到信用卡「${cardName}」`);if(goalName&&!g)warnings.push(`記帳第 ${i+2} 列找不到存錢目標「${goalName}」`);return{id:uid()+3000+i,type,date,category:String(rowValue(r,['分類'])||(type==='saving'?'存款':'其他')).trim(),amount:toNum(rowValue(r,['金額'])),accountId:d?`debt:${d.id}`:a?`asset:${a.id}`:'',goalId:g?String(g.id):'',importance:1,note:String(rowValue(r,['備註'])||'').trim(),receipt:'',systemGenerated:false,syncApplied:false,importedFromExcel:true,sourceAccountName:assetName,sourceCardName:cardName,sourceGoalName:goalName}}).filter(x=>x.date&&x.amount>0);
 const debtTypes=[...new Set([...debtTypeRows.map(r=>String(rowValue(r,['類型','負債類型','分類'])||'').trim()).filter(Boolean),...debts.map(x=>x.type).filter(Boolean)])];
 const assetTypes=[...new Set([...assetTypeRows.map(r=>String(rowValue(r,['類型','資產類型','分類'])||'').trim()).filter(Boolean),...assets.map(x=>x.type).filter(Boolean)])];
 const incCats=incRows.map(r=>String(rowValue(r,['分類'])||'').trim()).filter(Boolean),expCats=expRows.map(r=>String(rowValue(r,['分類'])||'').trim()).filter(Boolean);
 if(!debtRows.length)warnings.push('找不到「負債狀況」工作表');if(!assetRows.length)warnings.push('找不到「資產狀況」工作表');if(!txRows.length)warnings.push('找不到「記帳」工作表');
 return{debts,assets,goals,transactions,debtTypes,assetTypes,categories:{income:incCats,expense:expCats,saving:['存款']},warnings};}
function readExcelFile(e){const f=e.target.files[0];if(!f)return;if(!window.XLSX){notify('Excel 讀取元件尚未載入，請連線後重新開啟 App');return}const r=new FileReader();r.onload=()=>{try{const wb=XLSX.read(r.result,{type:'array',cellDates:true});excelPreviewData=parseExcelWorkbook(wb);excelPreviewData.fileName=f.name;$('excelFileName').innerHTML=`<strong>${esc(f.name)}</strong><div class="small">已完成解析，請確認筆數後再匯入。</div>`;const x=excelPreviewData,items=[['負債',x.debts.length],['資產',x.assets.length],['存錢目標',x.goals.length],['記帳',x.transactions.length],['收入分類',x.categories.income.length],['支出分類',x.categories.expense.length],['負債類型',x.debtTypes.length],['資產類型',x.assetTypes.length]];$('excelCounts').innerHTML=items.map(([n,c])=>`<div class="metric"><small>${n}</small><strong>${c} 筆</strong></div>`).join('');$('excelWarnings').innerHTML=x.warnings.length?x.warnings.slice(0,20).map(w=>`<div class="alert warn">${esc(w)}</div>`).join(''):'<div class="alert"><strong>格式檢查完成</strong><div class="small">未發現需注意的欄位。</div></div>';$('excelImportIntro').classList.add('hidden');$('excelImportPreview').classList.remove('hidden')}catch(err){notify('Excel 格式無法讀取');console.error(err)}};r.readAsArrayBuffer(f)}
function txFingerprint(x){return[x.date,x.type,x.category,Number(x.amount||0),x.note||'',x.sourceAccountName||'',x.sourceCardName||'',x.sourceGoalName||''].join('|')}
function relinkImportedTransactions(data){const assetByName=new Map(state.assets.map(x=>[x.name,x])),debtByName=new Map(state.debts.map(x=>[x.name,x])),goalByName=new Map(state.goals.map(x=>[x.name,x]));data.transactions.forEach(tx=>{const a=assetByName.get(tx.sourceAccountName),d=debtByName.get(tx.sourceCardName),g=goalByName.get(tx.sourceGoalName);tx.accountId=d?`debt:${d.id}`:a?`asset:${a.id}`:'';tx.goalId=g?String(g.id):''})}
function confirmExcelImport(){
 if(!excelPreviewData)return;
 const mode=$('excelImportMode').value,data=structuredClone(excelPreviewData),before=structuredClone(state);
 try{
  if(mode==='replace'){
   state.debts=data.debts;
   state.assets=data.assets;
   state.goals=data.goals;
   relinkImportedTransactions(data);
   state.transactions=data.transactions;
   state.categories={
    expense:[...new Set([...DEFAULT_CATEGORIES.expense,...data.categories.expense])],
    income:[...new Set([...DEFAULT_CATEGORIES.income,...data.categories.income])],
    saving:['存款']
   };
   state.debtTypes=[...new Set([...DEFAULT_DEBT_TYPES,...data.debtTypes,...state.debts.map(x=>x.type)])];
   state.assetTypes=[...new Set([...DEFAULT_ASSET_TYPES,...data.assetTypes,...state.assets.map(x=>x.type)])];
  }else{
   const mergeNamed=(old,add)=>{
    const map=new Map(old.map(x=>[`${x.type||''}|${x.name}`,x]));
    add.forEach(x=>{
     const k=`${x.type||''}|${x.name}`;
     if(map.has(k))Object.assign(map.get(k),x,{id:map.get(k).id});
     else old.push(x)
    });
    return old
   };
   state.debts=mergeNamed(state.debts,data.debts);
   state.assets=mergeNamed(state.assets,data.assets);
   const gm=new Map(state.goals.map(x=>[x.name,x]));
   data.goals.forEach(x=>gm.has(x.name)?Object.assign(gm.get(x.name),x,{id:gm.get(x.name).id}):state.goals.push(x));
   relinkImportedTransactions(data);
   const existing=new Set(state.transactions.map(txFingerprint));
   data.transactions.forEach(x=>{if(!existing.has(txFingerprint(x)))state.transactions.push(x)});
   state.categories.expense=[...new Set([...state.categories.expense,...data.categories.expense])];
   state.categories.income=[...new Set([...state.categories.income,...data.categories.income])];
   state.debtTypes=[...new Set([...state.debtTypes,...data.debtTypes,...state.debts.map(x=>x.type)])];
   state.assetTypes=[...new Set([...state.assetTypes,...data.assetTypes,...state.assets.map(x=>x.type)])];
  }
  state.lastExcelImport={date:new Date().toISOString(),file:data.fileName||'',counts:{debts:data.debts.length,assets:data.assets.length,goals:data.goals.length,transactions:data.transactions.length,debtTypes:data.debtTypes.length,assetTypes:data.assetTypes.length}};
  localStorage.setItem(KEY,JSON.stringify(state));
  renderAll();
  closeModal('excelImportModal');
  notify('Excel 匯入完成')
 }catch(err){
  state=before;
  console.error(err);
  notify('匯入失敗，原資料未變更')
 }
}

// ===== V10.2 雲端設定、備份與全部重置 =====
function freshInitialState(){
  const base=structuredClone(D);
  base.startDate=today();
  return base;
}

function exportData(){
  try{
    const blob=new Blob([JSON.stringify({version:'11.1',exportedAt:new Date().toISOString(),data:state},null,2)],{type:'application/json'});
    const url=URL.createObjectURL(blob),a=document.createElement('a');
    a.href=url;a.download=`restart-backup-${today()}.json`;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url);
    notify('備份已匯出');
  }catch(e){console.error(e);notify('備份匯出失敗')}
}

function importData(event){
  const file=event.target.files?.[0];if(!file)return;
  const reader=new FileReader();
  reader.onload=()=>{try{const parsed=JSON.parse(reader.result);const incoming=parsed?.data||parsed;if(!incoming||typeof incoming!=='object')throw new Error('格式錯誤');localStorage.setItem(KEY,JSON.stringify(incoming));state=load();renderAll();notify('備份已匯入')}catch(e){console.error(e);notify('備份格式無法讀取')}finally{event.target.value=''}};
  reader.readAsText(file);
}

async function deleteCloudRowsForUser(user){
  if(!user)return [];
  const errors=[];
  const tables=['transactions','photos','finance_reports','excel_import_logs','diaries','checkins','relapses','categories','saving_goals','debts','assets','settings'];
  for(const table of tables){
    try{const {error}=await cloud.from(table).delete().eq('user_id',user.id);if(error)errors.push(`${table}: ${error.message}`)}catch(e){errors.push(`${table}: ${e.message||e}`)}
  }
  return errors;
}

async function removeStorageTree(prefix){
  const paths=[];
  async function walk(folder){
    const {data,error}=await cloud.storage.from('restart-images').list(folder,{limit:1000});
    if(error){if(!/not found/i.test(error.message||''))console.warn('Storage list',error);return}
    for(const item of data||[]){
      const path=folder?`${folder}/${item.name}`:item.name;
      if(item.id)paths.push(path);else await walk(path);
    }
  }
  await walk(prefix);
  if(paths.length){const {error}=await cloud.storage.from('restart-images').remove(paths);if(error)console.warn('Storage remove',error)}
}

async function resetAll(){
  if(!confirm('這會清除所有負債、資產、記帳、日記、簽到、照片與設定，並回到全新初始狀態。\n\n確定繼續？'))return;
  const phrase=prompt('為避免誤觸，請輸入「全部重置」後繼續：','');
  if(phrase!=='全部重置'){notify('已取消重置');return}
  const button=document.querySelector('button[onclick="resetAll()"]');
  if(button){button.disabled=true;button.textContent='重置中…'}
  try{
    const {data}=await cloud.auth.getUser();
    const user=data?.user||null;
    const errors=await deleteCloudRowsForUser(user);
    if(user)await removeStorageTree(user.id);
    localStorage.removeItem(KEY);
    state=freshInitialState();
    localStorage.setItem(KEY,JSON.stringify(state));
    renderAll();
    if(user)await window.RestartCloudSettings?.save?.();
    closeSOS?.();
    showPage('home');
    if(errors.length){console.warn('部分雲端資料重置失敗',errors);notify('已回到初始設定；部分雲端資料稍後再同步')}else notify('已全部重置並回到初始設定');
  }catch(e){
    console.error('全部重置失敗',e);
    // 即使雲端暫時失敗，也確保手機畫面能回到初始狀態。
    localStorage.removeItem(KEY);state=freshInitialState();localStorage.setItem(KEY,JSON.stringify(state));renderAll();notify('本機已回到初始設定');
  }finally{
    if(button){button.disabled=false;button.textContent='全部重置'}
  }
}


