const WEEKLY_STYLE_REWARDS=['week-1','week-2','week-3','week-4','week-5','week-6'];
const DAILY_TOKEN_REWARDS=[1,1,2,2,3,3,1];
const STARTER_OWNED=['hair-rgb-155-103-055','eye-round','eye-brown','expression-soft','top-white','bottom-black','shoes-white'];
let shopPreviewItemId='';
function equippedWithItem(item){const eq={...state.game.equipped};if(!item)return eq;if(item.slot==='set'){eq.set=item.id;eq.top='';eq.bottom=''}else{if(item.slot==='top'||item.slot==='bottom')eq.set='';eq[item.slot]=item.id}return eq}
function itemAvatarThumb(item){const eq=equippedWithItem(item);eq.__thumbSlot=item?.slot||'';return avatarSvg('thumb',eq)}

function dayBefore(dateStr){const d=new Date(dateStr+'T12:00:00');d.setDate(d.getDate()-1);return d.toISOString().slice(0,10)}
function ensureGameState(){
 if(!state.game||typeof state.game!=='object')state.game={};
 state.game.character=state.game.character||''; state.game.tokens=Math.max(0,Number(state.game.tokens||0));
 if(!state.game.initialGrantV112){state.game.tokens+=100;state.game.initialGrantV112=true}
 state.game.owned=Array.isArray(state.game.owned)?state.game.owned:[];
 state.game.equipped=state.game.equipped||{};
 const old=state.game.equipped;
 if(old.hat&&!old.headAccessory)old.headAccessory=old.hat;if(old.outfit&&!old.set)old.set=old.outfit;if(old.accessory&&!old.handheld)old.handheld=old.accessory;
 const legacyHairColors={'hair-brown':'hair-rgb-155-103-055','hair-black':'hair-rgb-025-020-022','hair-gold':'hair-rgb-255-236-062','hair-pink':'hair-rgb-255-086-098'};
 if(legacyHairColors[old.hairColor])old.hairColor=legacyHairColors[old.hairColor];
 state.game.owned=state.game.owned.map(id=>legacyHairColors[id]||id);
 WARDROBE_CATEGORIES.forEach(([slot])=>{if(!(slot in old))old[slot]=''});
 state.game.rewardedDays=Array.isArray(state.game.rewardedDays)?state.game.rewardedDays:[];
 state.game.journalRewardedDays=Array.isArray(state.game.journalRewardedDays)?state.game.journalRewardedDays:[];
 state.game.signinDay=Math.min(7,Math.max(0,Number(state.game.signinDay||0)));state.game.completedCycles=Math.max(0,Number(state.game.completedCycles||0));
 state.game.lastRewardDate=state.game.lastRewardDate||'';state.game.lastRewardText=state.game.lastRewardText||'';state.game.shopCategory=state.game.shopCategory||'hair';state.game.closetCategory=state.game.closetCategory||'hair';
 if(!state.categories.expense.includes('復賭'))state.categories.expense.push('復賭');
}
function coinIcon(cls='coin-inline'){return `<img class="${cls}" src="coin-icon.png" alt="戒賭幣">`}
function itemById(id){return GAME_ITEMS.find(x=>x.id===id)}
function hairShape(style,color){const s=Number(style||1);const fringe=['M43 38 Q70 9 97 38 Q90 18 70 17 Q50 18 43 38','M41 38 Q70 7 99 38 Q93 19 78 18 Q65 31 42 30','M39 41 Q51 13 70 17 Q91 9 101 40 Q84 27 70 22 Q58 35 39 41','M41 38 Q57 12 72 18 Q91 8 100 38 Q83 22 60 26','M39 40 Q50 12 72 17 Q93 12 101 41 Q84 30 70 25 Q53 37 39 40'][s%5];return `<path d="${fringe}" fill="${color}"/><path d="M39 39 Q39 16 70 14 Q102 16 101 42 L96 64 Q91 46 88 39 Q70 27 51 40 Q47 48 44 63 Z" fill="${color}"/>`}
function avatarSvg(size='full',equippedOverride=null){
 ensureGameState();const eq=equippedOverride||state.game.equipped,character=STARTER_CHARACTERS.find(x=>x.id===state.game.character)||STARTER_CHARACTERS[0];
 const hair=itemById(eq.hair)||itemById(character.hair),hairColor=itemById(eq.hairColor)||itemById('hair-brown'),eye=itemById(eq.eyeColor)||itemById('eye-brown');
 const top=itemById(eq.top)||itemById('top-white'),bottom=itemById(eq.bottom)||itemById('bottom-black'),set=itemById(eq.set),shoes=itemById(eq.shoes)||itemById('shoes-white');
 const eyeShape=eq.eyeShape||'eye-round',expression=eq.expression||'expression-soft';const face=itemById(eq.faceAccessory),head=itemById(eq.headAccessory),hand=itemById(eq.handAccessory),ear=itemById(eq.earrings),held=itemById(eq.handheld);
 const outfitColor=(set||top)?.color||'#fafafa',bottomColor=(set?.color||bottom?.color||'#292d34');
 const eyes=eyeShape==='eye-smile'?`<path d="M54 56 Q59 50 64 56 M76 56 Q81 50 86 56" fill="none" stroke="${eye.color}" stroke-width="3" stroke-linecap="round"/>`:eyeShape==='eye-sharp'?`<path d="M53 54 L64 57 M76 57 L87 54" stroke="${eye.color}" stroke-width="4" stroke-linecap="round"/>`:`<ellipse cx="59" cy="56" rx="5" ry="7" fill="${eye.color}"/><ellipse cx="81" cy="56" rx="5" ry="7" fill="${eye.color}"/><circle cx="57" cy="53" r="1.5" fill="#fff"/><circle cx="79" cy="53" r="1.5" fill="#fff"/>`;
 const mouth=expression==='expression-happy'?'<path d="M64 68 Q70 75 76 68" fill="#d96c6c" stroke="#7d4545" stroke-width="1.5"/>':expression==='expression-calm'?'<path d="M66 69 Q70 67 74 69" fill="none" stroke="#7d4545" stroke-width="1.5"/>':'<path d="M66 68 Q70 72 74 68" fill="none" stroke="#7d4545" stroke-width="1.5"/>';
 return `<svg class="chibi-svg ${size}" viewBox="0 0 140 180" xmlns="http://www.w3.org/2000/svg"><ellipse cx="70" cy="170" rx="45" ry="8" fill="rgba(0,0,0,.12)"/><circle cx="70" cy="53" r="31" fill="#ffd8bc"/>${hairShape(hair?.style||1,hairColor.color)}${eyes}${mouth}${face?.id==='face-blush'?'<ellipse cx="47" cy="66" rx="7" ry="3" fill="#ef9a9a" opacity=".65"/><ellipse cx="93" cy="66" rx="7" ry="3" fill="#ef9a9a" opacity=".65"/>':''}${face?.id==='face-freckle'?'<g fill="#b6785f"><circle cx="48" cy="65" r="1"/><circle cx="52" cy="67" r="1"/><circle cx="88" cy="67" r="1"/><circle cx="92" cy="65" r="1"/></g>':''}${face?.id==='face-glasses'?'<g fill="none" stroke="#563f35" stroke-width="2"><circle cx="57" cy="57" r="9"/><circle cx="83" cy="57" r="9"/><path d="M66 57 H74"/></g>':''}<rect x="52" y="78" width="36" height="45" rx="14" fill="${outfitColor}"/><rect x="44" y="82" width="12" height="38" rx="6" fill="#ffd8bc"/><rect x="84" y="82" width="12" height="38" rx="6" fill="#ffd8bc"/><rect x="51" y="113" width="18" height="38" rx="8" fill="${bottomColor}"/><rect x="71" y="113" width="18" height="38" rx="8" fill="${bottomColor}"/><rect x="48" y="145" width="25" height="13" rx="6" fill="${shoes.color||'#fff'}" stroke="#ddd"/><rect x="68" y="145" width="25" height="13" rx="6" fill="${shoes.color||'#fff'}" stroke="#ddd"/>${head?`<text x="70" y="23" text-anchor="middle" font-size="24">${head.icon}</text>`:''}${ear?`<text x="37" y="64" font-size="12">${ear.icon}</text><text x="93" y="64" font-size="12">${ear.icon}</text>`:''}${hand?`<text x="91" y="116" font-size="15">${hand.icon}</text>`:''}${held?`<text x="101" y="127" font-size="27">${held.icon}</text>`:''}</svg>`
}
function renderGameHome(){ensureGameState();if($('homeAvatar'))$('homeAvatar').innerHTML=state.game.character?avatarSvg('mini'):'🧑';if($('homeTokens'))$('homeTokens').textContent=state.game.tokens;if($('homeGameText'))$('homeGameText').textContent=state.game.character?'裝扮角色、領取簽到獎勵':'建立你的角色'}
function renderCharacterChoices(){const box=$('characterChoices');if(!box)return;box.innerHTML=['male','female'].map(g=>`<section class="starter-group"><h3>${g==='male'?'♂ 男生角色':'♀ 女生角色'}</h3><div class="starter-grid">${STARTER_CHARACTERS.filter(x=>x.gender===g).map(x=>`<button class="starter-character ${state.game.pendingCharacter===x.id?'selected':''}" onclick="previewCharacter('${x.id}')"><span>${x.name}</span>${avatarSvgForStarter(x)}</button>`).join('')}</div></section>`).join('')}
function avatarSvgForStarter(char){const oldChar=state.game.character,oldHair=state.game.equipped.hair;state.game.character=char.id;state.game.equipped.hair=char.hair;const out=avatarSvg('select');state.game.character=oldChar;state.game.equipped.hair=oldHair;return out}
function previewCharacter(id){state.game.pendingCharacter=id;renderCharacterChoices();$('confirmCharacterBtn').disabled=false}
function openGame(){ensureGameState();$('gameSetup').classList.toggle('hidden',!!state.game.character);$('gameMain').classList.toggle('hidden',!state.game.character);if(!state.game.character){state.game.pendingCharacter='';renderCharacterChoices();$('confirmCharacterBtn').disabled=true}renderGame();openModal('gameModal')}
function confirmCharacter(){ensureGameState();const char=STARTER_CHARACTERS.find(x=>x.id===state.game.pendingCharacter);if(!char)return notify('請先選擇角色');state.game.character=char.id;state.game.owned=[...new Set([...state.game.owned,...STARTER_OWNED,char.hair])];Object.assign(state.game.equipped,{hair:char.hair,hairColor:'hair-rgb-155-103-055',eyeShape:'eye-round',eyeColor:'eye-brown',expression:'expression-soft',top:'top-white',bottom:'bottom-black',set:'',shoes:'shoes-white'});save();$('gameSetup').classList.add('hidden');$('gameMain').classList.remove('hidden');renderGame();notify('角色建立完成，初始服裝已放入衣櫃')}
function nextWeeklyReward(){ensureGameState();const id=WEEKLY_STYLE_REWARDS[state.game.completedCycles%WEEKLY_STYLE_REWARDS.length];return itemById(id)}
function renderSigninRewards(){ensureGameState();if(!$('signinRewards'))return;const activeDay=state.game.signinDay===7?7:state.game.signinDay+1,next=nextWeeklyReward();$('signinCycleText').textContent=`第 ${state.game.completedCycles+1} 輪｜第 7 天送限定造型`;$('signinStreakText').textContent=`連續 ${state.game.signinDay} 天`;$('signinRewards').innerHTML=[1,2,3,4,5,6,7].map(day=>{const done=day<=state.game.signinDay,current=day===activeDay&&!state.checkins.includes(today()),reward=day===7?`<div class="signin-style">${next?.icon||'🎁'}</div><span>限定造型</span>`:`${coinIcon('signin-coin')}<span>+${DAILY_TOKEN_REWARDS[day-1]}</span>`;return `<div class="signin-day ${done?'done':''} ${current?'current':''}"><b>Day ${day}</b>${reward}${done?'<i>✓</i>':''}</div>`}).join('');$('signinRewardNote').textContent=state.game.lastRewardText||`今天完成「今天不賭」即可領取 Day ${activeDay} 獎勵。`}
function renderGame(){ensureGameState();if(!$('gameAvatar'))return;const browser=document.querySelector('.avatar-browser');if(browser)browser.dataset.category=state.game.shopCategory||state.game.closetCategory||'hair';const previewItem=itemById(shopPreviewItemId);$('gameAvatar').innerHTML=state.game.character?avatarSvg('full',previewItem?equippedWithItem(previewItem):null):'';$('gameTokens').textContent=state.game.tokens;if($('previewItemName'))$('previewItemName').textContent=previewItem?`試穿：${previewItem.name}`:'目前穿搭';renderSigninRewards();renderCloset();renderShop();renderGameHome();renderPurchaseBar()}
function showGameTab(tab,btn){document.querySelectorAll('.studio-mode-tabs button').forEach(x=>x.classList.remove('active'));btn?.classList.add('active');$('gameCloset').classList.toggle('hidden',tab!=='closet');$('gameShop').classList.toggle('hidden',tab!=='shop');if(tab==='closet')cancelShopPreview(false)}
function categoryTabs(mode){const current=state.game[mode==='shop'?'shopCategory':'closetCategory'];return `<div class="wardrobe-tabs">${WARDROBE_CATEGORIES.map(([id,label])=>`<button class="${current===id?'active':''}" onclick="setWardrobeCategory('${mode}','${id}')">${label}</button>`).join('')}</div>`}
function setWardrobeCategory(mode,id){state.game[mode==='shop'?'shopCategory':'closetCategory']=id;if(mode==='shop')shopPreviewItemId='';save();renderGame()}
function renderCloset(){ensureGameState();const slot=state.game.closetCategory,label=WARDROBE_CATEGORIES.find(x=>x[0]===slot)?.[1]||'';const items=GAME_ITEMS.filter(x=>x.slot===slot&&state.game.owned.includes(x.id));$('gameCloset').innerHTML=categoryTabs('closet')+`<div class="studio-heading"><strong>${label}</strong><span class="muted small">點選立即穿上</span></div><div class="studio-grid">${!['hair','hairColor','eyeShape','eyeColor','expression','top','bottom','shoes'].includes(slot)?`<button class="studio-item ${!state.game.equipped[slot]?'active':''}" onclick="equipGameItem('${slot}','')"><div class="studio-thumb empty-thumb">無</div><span>不裝備</span></button>`:''}${items.map(x=>`<button class="studio-item ${state.game.equipped[slot]===x.id?'active':''}" onclick="equipGameItem('${slot}','${x.id}')"><div class="studio-thumb">${itemAvatarThumb(x)}</div><span>${x.name}</span>${x.limited?'<small>簽到限定</small>':''}</button>`).join('')||'<div class="empty">這個分類尚無物品</div>'}</div>`}
function renderShop(){ensureGameState();const slot=state.game.shopCategory,label=WARDROBE_CATEGORIES.find(x=>x[0]===slot)?.[1]||'';const items=GAME_ITEMS.filter(x=>x.slot===slot&&!x.limited&&!x.starter&&!state.game.owned.includes(x.id));$('gameShop').innerHTML=categoryTabs('shop')+`<div class="studio-heading"><strong>${label}</strong><span class="muted small">點商品即時試穿</span></div>${items.length?`<div class="studio-grid">${items.map(x=>`<button class="studio-item shop-product ${shopPreviewItemId===x.id?'active':''}" onclick="previewShopItem('${x.id}')"><div class="studio-thumb">${itemAvatarThumb(x)}</div><span>${x.name}</span><small class="shop-price">${coinIcon()} ${x.price}</small></button>`).join('')}</div>`:'<div class="empty collected">🎉 此分類已全部收藏！</div>'}`}
function previewShopItem(id){const item=itemById(id);if(!item||state.game.owned.includes(id))return;shopPreviewItemId=id;renderGame()}
function renderPurchaseBar(){const bar=$('gamePurchaseBar');if(!bar)return;const item=itemById(shopPreviewItemId);bar.classList.toggle('hidden',!item);if(!item)return;$('purchaseItemName').textContent=`${item.name}・${item.price} 枚`;const btn=$('confirmPurchaseBtn');btn.disabled=state.game.tokens<item.price;btn.textContent=state.game.tokens<item.price?'戒賭幣不足':'確認購買'}
function cancelShopPreview(shouldRender=true){shopPreviewItemId='';if(shouldRender)renderGame()}
function confirmShopPurchase(){const id=shopPreviewItemId,item=itemById(id);if(!item)return;if(state.game.owned.includes(id)){cancelShopPreview();return}if(state.game.tokens<item.price)return notify('戒賭幣不足');state.game.tokens-=item.price;state.game.owned.push(id);equipGameItem(item.slot,id,false);shopPreviewItemId='';save();renderGame();notify(`已購買 ${item.name}，已加入衣櫃並穿上`)}
function buyGameItem(id){shopPreviewItemId=id;confirmShopPurchase()}
function equipGameItem(slot,id,doSave=true){ensureGameState();if(slot==='set'&&id){state.game.equipped.top='';state.game.equipped.bottom=''}if((slot==='top'||slot==='bottom')&&id)state.game.equipped.set='';state.game.equipped[slot]=id;if(doSave){save();renderGame();notify(id?'已換上裝扮':'已卸下裝扮')}}
function animateGameAvatar(){const el=$('gameAvatar');if(!el)return;el.classList.remove('avatar-bounce');void el.offsetWidth;el.classList.add('avatar-bounce')}
function grantSigninReward(){ensureGameState();const yesterday=dayBefore(today());if(state.game.lastRewardDate!==yesterday)state.game.signinDay=0;state.game.signinDay+=1;const day=state.game.signinDay,coinReward=DAILY_TOKEN_REWARDS[day-1]||1;state.game.tokens+=coinReward;let msg=`Day ${day}：獲得 ${coinReward} 枚戒賭幣`;if(day===7){const item=nextWeeklyReward();if(item&&!state.game.owned.includes(item.id)){state.game.owned.push(item.id);state.game.equipped[item.slot]=item.id;msg+=`，並獲得限定造型「${item.name}」`}else{state.game.tokens+=10;msg+='，限定造型已擁有，改送 10 枚戒賭幣'}state.game.completedCycles+=1;state.game.signinDay=0}state.game.lastRewardDate=today();state.game.lastRewardText=msg;state.game.rewardedDays.push(today());return msg}
function checkIn(){ensureGameState();if(!state.checkins.includes(today())){state.checkins.push(today());state.best=Math.max(state.best||0,currentStreak());const msg=state.game.rewardedDays.includes(today())?'今天也成功了':grantSigninReward();save();notify(msg)}else notify('今天已經簽到')}

let relapseDraft={reason:'',loss:0};
function setRelapseStep(n){[1,2,3].forEach(i=>$(`relapseStep${i}`).classList.toggle('hidden',i!==n))}
function recordRelapse(){relapseDraft={reason:'',loss:0};$('relapseReasonInput').value='';$('relapseLossInput').value='';setRelapseStep(1);openModal('relapseModal')}
function closeRelapseFlow(){closeModal('relapseModal')}
function relapseResisted(){closeRelapseFlow();notify('你忍住了，這次不計算復賭')}
function relapseNextReason(){setRelapseStep(2);setTimeout(()=>$('relapseReasonInput').focus(),100)}
function relapseNextLoss(){const reason=$('relapseReasonInput').value.trim();if(!reason)return notify('請填寫復賭原因');relapseDraft.reason=reason;const opts=[...state.assets.map(a=>`<option value="asset:${a.id}">資產｜${esc(a.name||a.type)}（${fmt(a.amount)}）</option>`),...state.debts.map(d=>`<option value="debt:${d.id}">負債｜${esc(d.name||d.type)}（${fmt(d.amount)}）</option>`)];$('relapseSourceSelect').innerHTML='<option value="">不連動帳戶或負債</option>'+opts.join('');setRelapseStep(3);setTimeout(()=>$('relapseLossInput').focus(),100)}
function finishRelapseFlow(){const raw=$('relapseLossInput').value;if(raw===''||!/^\d+(\.\d+)?$/.test(raw))return notify('請輸入本次損失金額');const loss=Number(raw);if(!Number.isFinite(loss)||loss<0)return notify('請輸入正確數字');const source=$('relapseSourceSelect').value;const streak=currentStreak();state.relapses.push({id:uid(),date:today(),reason:relapseDraft.reason,loss,streak});state.best=Math.max(state.best||0,streak);state.checkins=[];state.journals.push({id:uid(),date:today(),mood:'很痛苦',urge:'復賭',text:`今天因為「${relapseDraft.reason}」，沒有控制住自己。\n\n這次共損失 ${fmt(loss)}。\n\n雖然今天跌倒了，但我願意誠實記錄，代表我沒有放棄。一次復賭不代表永遠失敗，我仍然可以重新開始。`});if(loss>0){const tx={id:uid(),type:'expense',date:today(),category:'復賭',amount:loss,accountId:source,goalId:'',importance:3,note:`復賭－${relapseDraft.reason}`,receipt:'',systemGenerated:true,syncApplied:true};applyTransaction(tx);state.transactions.push(tx)}save();closeRelapseFlow();notify('已記錄。滑倒了沒關係，重新開始')}

window.RestartApp={
  getState:()=>state,
  persistLocal:()=>{localStorage.setItem(KEY,JSON.stringify(state));renderAll()},
  resetLocal:()=>{localStorage.removeItem(KEY);state=freshInitialState();localStorage.setItem(KEY,JSON.stringify(state));renderAll()},
  defaults:()=>freshInitialState(),
  render:renderAll
};

window.addEventListener('DOMContentLoaded',()=>{
  renderAll();
  if('serviceWorker' in navigator)navigator.serviceWorker.register('./sw.js').catch(e=>console.warn('SW',e));
});

